  }
}

/* ==========================================================================
   Revolucion Timeline — M003/S02/T02
   Animated 1800-1860 timeline for #periodo-revolucion.
   Extends the .colonial-timeline pattern; uses --color-revolucion (#74acdf).
   Scoped to .revolucion-timeline — does not affect other sections.
   ========================================================================== */

.revolucion-timeline {
  max-width: 800px;
  margin: var(--space-2xl) auto var(--space-lg);
  padding: var(--space-xl) var(--space-lg);
  background: var(--color-card-bg);
  border: 1px solid var(--color-card-border);
  border-radius: 6px;
  box-shadow: var(--shadow-card);
  text-align: center;
}

.revolucion-timeline__title {
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--color-text);
  margin-bottom: var(--space-xs);
}

.revolucion-timeline__subtitle {
  font-family: var(--font-body);
  font-size: 0.78rem;
  font-weight: 400;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--color-text-muted);
  margin-bottom: var(--space-xl);
}

.revolucion-timeline__track {
  position: relative;
  height: 4px;
  background: color-mix(in srgb, var(--color-revolucion) 25%, transparent);
  border-radius: 2px;
  margin: 3.5rem 1rem 3.5rem;
}

/* Animated progress bar */
.revolucion-timeline__progress {
  position: absolute;
  top: 0;
  left: 0;
  height: 100%;
  width: 0;
  background: linear-gradient(90deg, var(--color-revolucion), color-mix(in srgb, var(--color-revolucion) 60%, #1a3a5c));
  border-radius: 2px;
  animation: rev-timeline-fill 2.5s var(--ease-out) forwards;
  animation-play-state: paused;
}

/* Start animation when parent becomes visible via IntersectionObserver */
.revolucion-timeline.reveal--visible .revolucion-timeline__progress {
  animation-play-state: running;
}

@keyframes rev-timeline-fill {
  from { width: 0; }
  to   { width: 100%; }
}

/* Individual date markers */
.revolucion-timeline__marker {
  position: absolute;
  left: var(--marker-pos);
  top: 50%;
  transform: translate(-50%, -50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  z-index: 2;
}

.revolucion-timeline__dot {
  display: block;
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: var(--color-bg);
  border: 3px solid color-mix(in srgb, var(--color-revolucion) 40%, transparent);
  opacity: 0;
  transform: scale(0);
}

/* Staggered dot entrance — 10 markers spread over 0.15s–2.3s
   Delays are proportional to each marker's position on the 1800-1860 timeline */
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(2) .revolucion-timeline__dot {
  animation: rev-marker-pop 400ms var(--ease-out) 0.15s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(3) .revolucion-timeline__dot {
  animation: rev-marker-pop 400ms var(--ease-out) 0.45s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(4) .revolucion-timeline__dot {
  animation: rev-marker-pop 400ms var(--ease-out) 0.65s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(5) .revolucion-timeline__dot {
  animation: rev-marker-pop 400ms var(--ease-out) 0.90s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(6) .revolucion-timeline__dot {
  animation: rev-marker-pop 400ms var(--ease-out) 1.05s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(7) .revolucion-timeline__dot {
  animation: rev-marker-pop 400ms var(--ease-out) 1.30s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(8) .revolucion-timeline__dot {
  animation: rev-marker-pop 400ms var(--ease-out) 1.45s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(9) .revolucion-timeline__dot {
  animation: rev-marker-pop 400ms var(--ease-out) 1.75s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(10) .revolucion-timeline__dot {
  animation: rev-marker-pop 400ms var(--ease-out) 2.05s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(11) .revolucion-timeline__dot {
  animation: rev-marker-pop 400ms var(--ease-out) 2.30s forwards;
}

@keyframes rev-marker-pop {
  0%   { opacity: 0; transform: scale(0); }
  60%  { opacity: 1; transform: scale(1.3); }
  100% { opacity: 1; transform: scale(1); background: var(--color-revolucion); border-color: var(--color-revolucion); }
}

/* Labels under dots */
.revolucion-timeline__label {
  position: absolute;
  top: 1.1rem;
  left: 50%;
  transform: translateX(-50%);
  white-space: nowrap;
  font-family: var(--font-display);
  font-size: 0.7rem;
  font-weight: 700;
  line-height: 1.3;
  color: var(--color-text);
  text-align: center;
  opacity: 0;
}

/* --above modifier: label appears ABOVE the track to prevent overlap in dense clusters */
.revolucion-timeline__marker--above .revolucion-timeline__label {
  top: auto;
  bottom: 1.1rem;
  transform: translateX(-50%);
}

.revolucion-timeline__label small {
  display: block;
  font-family: var(--font-body);
  font-size: 0.6rem;
  font-weight: 400;
  color: var(--color-text-muted);
  white-space: nowrap;
}

/* Labels appear slightly after their dot */
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(2) .revolucion-timeline__label {
  animation: rev-label-fade 400ms var(--ease-out) 0.35s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(3) .revolucion-timeline__label {
  animation: rev-label-fade 400ms var(--ease-out) 0.65s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(4) .revolucion-timeline__label {
  animation: rev-label-fade 400ms var(--ease-out) 0.85s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(5) .revolucion-timeline__label {
  animation: rev-label-fade 400ms var(--ease-out) 1.10s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(6) .revolucion-timeline__label {
  animation: rev-label-fade 400ms var(--ease-out) 1.25s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(7) .revolucion-timeline__label {
  animation: rev-label-fade 400ms var(--ease-out) 1.50s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(8) .revolucion-timeline__label {
  animation: rev-label-fade 400ms var(--ease-out) 1.65s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(9) .revolucion-timeline__label {
  animation: rev-label-fade 400ms var(--ease-out) 1.95s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(10) .revolucion-timeline__label {
  animation: rev-label-fade 400ms var(--ease-out) 2.25s forwards;
}
.revolucion-timeline.reveal--visible .revolucion-timeline__marker:nth-child(11) .revolucion-timeline__label {
  animation: rev-label-fade 400ms var(--ease-out) 2.50s forwards;
}

@keyframes rev-label-fade {
  from { opacity: 0; transform: translateX(-50%) translateY(4px); }
  to   { opacity: 1; transform: translateX(-50%) translateY(0); }
}

@keyframes rev-label-fade-above {
  from { opacity: 0; transform: translateX(-50%) translateY(-4px); }
  to   { opacity: 1; transform: translateX(-50%) translateY(0); }
}

/* --above markers use the upward-entering label animation */
.revolucion-timeline.reveal--visible .revolucion-timeline__marker--above .revolucion-timeline__label {
  animation-name: rev-label-fade-above;
}

/* Hover on markers */
.revolucion-timeline__marker:hover .revolucion-timeline__dot {
  border-color: var(--color-text) !important;
  transform: scale(1.3);
}

/* ---- Responsive: revolucion timeline — mobile ---- */

@media (max-width: 48rem) {
  .revolucion-timeline {
    margin: var(--space-xl) auto var(--space-md);
    padding: var(--space-lg) var(--space-md);
  }

  .revolucion-timeline__track {
    margin: 3rem 0.5rem 3rem;
  }

  .revolucion-timeline__label {
    font-size: 0.58rem;
  }

  .revolucion-timeline__label small {
    font-size: 0.48rem;
  }

  .revolucion-timeline__dot {
    width: 10px;
    height: 10px;
    border-width: 2px;
  }
}

/* At 320px: hide sublabels to avoid density crowding (10 markers in ~280px) */
@media (max-width: 30rem) {
  .revolucion-timeline__label small {
    display: none;
  }

  .revolucion-timeline__track {
    margin: 1.5rem 0 2.5rem;
  }

  .revolucion-timeline__label {
    font-size: 0.54rem;
  }
}

/* ---- Accessibility: skip timeline animations for reduced-motion users ---- */

@media (prefers-reduced-motion: reduce) {
  .revolucion-timeline__progress {
    animation: none;
    width: 100%;
  }

  .revolucion-timeline__dot {
    opacity: 1;
    transform: scale(1);
    animation: none !important;
    background: var(--color-revolucion);
    border-color: var(--color-revolucion);
  }

  .revolucion-timeline__label {
    opacity: 1;
    transform: translateX(-50%);
    animation: none !important;
  }

  /* --above labels (above track) — same final state for reduced-motion */
  .revolucion-timeline__marker--above .revolucion-timeline__label {
    transform: translateX(-50%);
  }
}

/* ==========================================================================
   Responsive Video Wrapper — T02: Infrastructure for video embeds
   ==========================================================================
   Ready for YouTube/Vimeo iframe embeds. Use: <div class="responsive-video"><iframe ...></div>
   ========================================================================== */

.responsive-video {
  max-width: 800px;
  margin: var(--space-2xl) auto var(--space-lg);
  text-align: center;
}

.responsive-video__heading {
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--color-text);
  margin-bottom: var(--space-xs);
}

.responsive-video__caption {
  font-family: var(--font-body);
  font-size: 0.82rem;
  color: var(--color-text-muted);
  margin-bottom: var(--space-md);
}

.responsive-video__wrapper {
  position: relative;
  aspect-ratio: 16 / 9;
  width: 100%;
  background: var(--color-sepia-light);
  border-radius: 6px;
  overflow: hidden;
  box-shadow: var(--shadow-card);
}

.responsive-video__wrapper iframe {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  border: 0;
}

@media (prefers-reduced-motion: reduce) {
  .responsive-video__wrapper iframe {
    /* Autoplay suppressed by browser; no additional action needed */
  }
}

/* =====================================================
   SUB-PERIOD STRUCTURE — #periodo-revolucion
   Added: T07 (M003/S01)
   ===================================================== */

/* Sub-period wrapper — groups cards for one historical phase */
.sub-period {
  margin-bottom: var(--space-3xl);
}

/* Sub-period title (h3 inside each .sub-period) */
.sub-period__title {
  font-family: var(--font-serif);
  font-size: clamp(1.15rem, 2.5vw, 1.5rem);
  font-weight: 600;
  color: var(--color-celeste-deep);
  letter-spacing: 0.01em;
  margin: 0 0 var(--space-xl) 0;
  padding-bottom: var(--space-sm);
  border-bottom: 2px solid rgba(116, 172, 223, 0.3);
  position: relative;
  display: flex;
  align-items: center;
  gap: var(--space-sm);
}

/* Decorative left accent bar on sub-period title */
.sub-period__title::before {
  content: '';
  display: inline-block;
  width: 4px;
  height: 1.1em;
  background: var(--color-celeste);
  border-radius: 2px;
  flex-shrink: 0;
}

/* Alberdi quote block between sub-periods */
.alberdi-quote {
  margin: var(--space-2xl) auto;
  max-width: var(--content-narrow);
  text-align: center;
}

/* Divider between sub-periods and connecting quote */
.sub-period + .alberdi-quote {
  padding-top: var(--space-xl);
  border-top: 1px solid rgba(116, 172, 223, 0.15);
}

/* Responsive: stack sub-period title on narrow viewports */
@media (max-width: 640px) {
  .sub-period__title {
    font-size: 1.05rem;
  }

  .sub-period {
    margin-bottom: var(--space-2xl);
  }
}


/* ==========================================================================
   Sub-navigation bar — #periodo-revolucion (M003/S02/T01)
   ==========================================================================
   Sticky below the main site-nav, tracks the currently visible sub-period.
   Mobile: horizontally scrollable. Desktop: centered flex layout.
   Active state: accent underline using --color-celeste-deep.
   ========================================================================== */

.sub-nav {
  position: sticky;
  /* Stack directly under the main site-nav (--nav-height: 3.5rem) */
  top: var(--nav-height);
  z-index: 90;
  display: flex;
  flex-wrap: nowrap;
  justify-content: center;
  gap: 0;
  padding: 0 var(--space-md);
  background: rgba(237, 230, 214, 0.96); /* --color-bg-warm with alpha */
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border-bottom: 1px solid rgba(116, 172, 223, 0.25);
  margin-bottom: var(--space-xl);
  /* Contain to #periodo-revolucion: rendered inside it, sticky only within that section */
}

.sub-nav__link {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.1rem;
  padding: var(--space-sm) var(--space-md);
  font-family: var(--font-display);
  font-size: 0.82rem;
  font-weight: 700;
  color: var(--color-text-muted);
  border-bottom: 3px solid transparent;
  transition:
    color var(--duration-normal) var(--ease-out),
    border-bottom-color var(--duration-normal) var(--ease-out),
    background var(--duration-normal) var(--ease-out);
  white-space: nowrap;
  text-decoration: none;
  cursor: pointer;
}

.sub-nav__link-label {
  display: block;
  font-family: var(--font-body);
  font-size: 0.62rem;
  font-weight: 400;
  letter-spacing: 0.07em;
  text-transform: uppercase;
  color: inherit;
  opacity: 0.75;
  transition: opacity var(--duration-normal) var(--ease-out);
}

.sub-nav__link:hover {
  color: var(--color-text);
  background: rgba(116, 172, 223, 0.06);
  border-bottom-color: var(--color-celeste-soft);
}

.sub-nav__link:hover .sub-nav__link-label {
  opacity: 1;
}

/* Active state — set by JS scroll tracking */
.sub-nav__link--active {
  color: var(--color-celeste-deep);
  border-bottom-color: var(--color-celeste);
}

.sub-nav__link--active .sub-nav__link-label {
  opacity: 1;
  color: var(--color-celeste-deep);
}

/* ---- Responsive: mobile ---- */

@media (max-width: 640px) {
  .sub-nav {
    justify-content: flex-start;
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none; /* Firefox */
    gap: 0;
    padding: 0 var(--space-sm);
  }

  /* Hide scrollbar on WebKit */
  .sub-nav::-webkit-scrollbar {
    display: none;
  }

  .sub-nav__link {
    padding: var(--space-sm) var(--space-sm);
    font-size: 0.75rem;
    flex-shrink: 0;
  }

content.text:
  .sub-nav__link-label {
    font-size: 0.55rem;
  }
}

@media (max-width: 30rem) {
  .sub-nav__link {
    padding: 0.4rem 0.5rem;
    font-size: 0.7rem;
  }

  .sub-nav__link-label {
    display: none; /* Too crowded at 320px — show years only */
  }
}

/* ---- Accessibility: prefers-reduced-motion ---- */

@media (prefers-reduced-motion: reduce) {
  .sub-nav__link,
  .sub-nav__link-label {
    transition: none;
  }
}

/* ==========================================================================
   Expand / Collapse toggle — detailed card content (M003/S02/T03)
   ==========================================================================
   Pattern:
   - <button class="card-expand-toggle" aria-expanded="false"> triggers JS
   - <div class="card-detail" hidden> holds the extra content
   - JS removes `hidden` and adds `.card-detail--expanded` on open
   ========================================================================== */

.card-expand-toggle {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  margin: 0.75rem 0 0;
  padding: 0.3rem 0;
  background: none;
  border: none;
  border-top: 1px solid color-mix(in srgb, var(--accent-celeste) 25%, transparent);
  color: var(--accent-celeste);
  font-family: inherit;
  font-size: 0.8rem;
  font-weight: 600;
  letter-spacing: 0.03em;
  cursor: pointer;
  width: 100%;
  text-align: left;
  transition: color 0.15s ease, border-color 0.15s ease;
}

.card-expand-toggle:hover,
.card-expand-toggle:focus-visible {
  color: var(--gold);
  border-color: var(--gold);
  outline: none;
}

.card-expand-toggle:focus-visible {
  outline: 2px solid var(--gold);
  outline-offset: 2px;
}

.card-expand-toggle__icon {
  display: inline-block;
  font-size: 0.65rem;
  transition: transform 0.25s ease;
  transform-origin: center;
}

.card-expand-toggle[aria-expanded="true"] .card-expand-toggle__icon {
  transform: rotate(180deg);
}

/* Detail panel — hidden baseline via HTML `hidden` attribute */
.card-detail {
  overflow: hidden;
  max-height: 0;
  opacity: 0;
  padding: 0;
  border-top: 1px solid color-mix(in srgb, var(--accent-celeste) 20%, transparent);
  margin-top: 0;
  transition: max-height 0.35s ease, opacity 0.25s ease, padding 0.25s ease, margin-top 0.25s ease;
}

.card-detail[hidden] {
  display: none;
}

.card-detail--expanded {
  max-height: 40rem; /* generous cap — real content is 2-4 short paragraphs */
  opacity: 1;
  padding: 0.75rem 0 0;
  margin-top: 0.5rem;
}

.card-detail p {
  font-size: 0.875rem;
  line-height: 1.65;
  color: var(--text-secondary, color-mix(in srgb, var(--text) 85%, transparent));
  margin: 0 0 0.65rem;
}

.card-detail p:last-child {
  margin-bottom: 0;
}

/* ---- Responsive: expand/collapse at 48rem ---- */
@media (max-width: 48rem) {
  .card-expand-toggle {
    min-height: 44px;
    display: flex;
    align-items: center;
  }
}

/* ---- Responsive: expand/collapse at 320px ---- */
@media (max-width: 30rem) {
  .card-expand-toggle {
    font-size: 0.75rem;
  }

  .card-detail p {
    font-size: 0.825rem;
  }
}

/* ---- Accessibility: skip expand transition for reduced-motion users ---- */
@media (prefers-reduced-motion: reduce) {
  .card-expand-toggle__icon,
  .card-detail {
    transition: none;
  }
}

/* ==========================================================================
   Nacional Timeline — M004/S02/T01
   Animated 1860–1900 timeline for #periodo-nacional.
   Extends the .colonial-timeline pattern; uses --color-nacional (#8b6b4a).
   7 markers at (year - 1860) / 40 * 100%.
   Scoped to .nacional-timeline — does not affect other sections.
   ========================================================================== */

.nacional-timeline {
  max-width: 800px;
  margin: var(--space-2xl) auto var(--space-lg);
  padding: var(--space-xl) var(--space-lg);
  background: var(--color-card-bg);
  border: 1px solid var(--color-card-border);
  border-radius: 6px;
  box-shadow: var(--shadow-card);
  text-align: center;
}

.nacional-timeline__title {
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--color-text);
  margin-bottom: var(--space-xs);
}

.nacional-timeline__subtitle {
  font-family: var(--font-body);
  font-size: 0.78rem;
  font-weight: 400;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--color-text-muted);
  margin-bottom: var(--space-xl);
}

.nacional-timeline__track {
  position: relative;
  height: 4px;
  background: color-mix(in srgb, var(--color-nacional) 25%, transparent);
  border-radius: 2px;
  margin: 2.5rem 1rem 3.5rem;
}

/* Animated progress bar */
.nacional-timeline__progress {
  position: absolute;
  top: 0;
  left: 0;
  height: 100%;
  width: 0;
  background: linear-gradient(90deg, var(--color-nacional), color-mix(in srgb, var(--color-nacional) 60%, #2a1a0a));
  border-radius: 2px;
  animation: nac-timeline-fill 2.5s var(--ease-out) forwards;
  animation-play-state: paused;
}

/* Start animation when parent becomes visible via IntersectionObserver */
.nacional-timeline.reveal--visible .nacional-timeline__progress {
  animation-play-state: running;
}

@keyframes nac-timeline-fill {
  from { width: 0; }
  to   { width: 100%; }
}

/* Individual date markers */
.nacional-timeline__marker {
  position: absolute;
  left: var(--marker-pos);
  top: 50%;
  transform: translate(-50%, -50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  z-index: 2;
}

.nacional-timeline__dot {
  display: block;
  width: 13px;
  height: 13px;
  border-radius: 50%;
  background: var(--color-bg);
  border: 3px solid color-mix(in srgb, var(--color-nacional) 40%, transparent);
  opacity: 0;
  transform: scale(0);
}

/* Staggered dot entrance — 7 markers proportionally spread over 0.15s–2.3s
   Delays track (year - 1860) / 40 timing relative to the 2.5s fill animation */
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(2) .nacional-timeline__dot {
  animation: nac-marker-pop 400ms var(--ease-out) 0.15s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(3) .nacional-timeline__dot {
  animation: nac-marker-pop 400ms var(--ease-out) 0.40s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(4) .nacional-timeline__dot {
  animation: nac-marker-pop 400ms var(--ease-out) 0.85s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(5) .nacional-timeline__dot {
  animation: nac-marker-pop 400ms var(--ease-out) 1.10s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(6) .nacional-timeline__dot {
  animation: nac-marker-pop 400ms var(--ease-out) 1.30s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(7) .nacional-timeline__dot {
  animation: nac-marker-pop 400ms var(--ease-out) 1.75s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(8) .nacional-timeline__dot {
  animation: nac-marker-pop 400ms var(--ease-out) 2.30s forwards;
}

@keyframes nac-marker-pop {
  0%   { opacity: 0; transform: scale(0); }
  60%  { opacity: 1; transform: scale(1.3); }
  100% { opacity: 1; transform: scale(1); background: var(--color-nacional); border-color: var(--color-nacional); }
}

/* Labels below dots (default: below track) */
.nacional-timeline__label {
  position: absolute;
  top: 1.1rem;
  left: 50%;
  transform: translateX(-50%);
  white-space: nowrap;
  font-family: var(--font-display);
  font-size: 0.7rem;
  font-weight: 700;
  line-height: 1.3;
  color: var(--color-text);
  text-align: center;
  opacity: 0;
}

/* --above modifier: label appears ABOVE the track (used for 1880 to avoid 45%/50% overlap) */
.nacional-timeline__marker--above .nacional-timeline__label {
  top: auto;
  bottom: 1.1rem;
  transform: translateX(-50%);
}

.nacional-timeline__label small {
  display: block;
  font-family: var(--font-body);
  font-size: 0.6rem;
  font-weight: 400;
  color: var(--color-text-muted);
  white-space: nowrap;
}

/* Labels appear slightly after their dot */
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(2) .nacional-timeline__label {
  animation: nac-label-fade 400ms var(--ease-out) 0.35s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(3) .nacional-timeline__label {
  animation: nac-label-fade 400ms var(--ease-out) 0.60s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(4) .nacional-timeline__label {
  animation: nac-label-fade 400ms var(--ease-out) 1.05s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(5) .nacional-timeline__label {
  animation: nac-label-fade-above 400ms var(--ease-out) 1.30s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(6) .nacional-timeline__label {
  animation: nac-label-fade 400ms var(--ease-out) 1.50s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(7) .nacional-timeline__label {
  animation: nac-label-fade 400ms var(--ease-out) 1.95s forwards;
}
.nacional-timeline.reveal--visible .nacional-timeline__marker:nth-child(8) .nacional-timeline__label {
  animation: nac-label-fade 400ms var(--ease-out) 2.50s forwards;
}

@keyframes nac-label-fade {
  from { opacity: 0; transform: translateX(-50%) translateY(4px); }
  to   { opacity: 1; transform: translateX(-50%) translateY(0); }
}

@keyframes nac-label-fade-above {
  from { opacity: 0; transform: translateX(-50%) translateY(-4px); }
  to   { opacity: 1; transform: translateX(-50%) translateY(0); }
}

/* --above markers use upward-entering label animation */
.nacional-timeline.reveal--visible .nacional-timeline__marker--above .nacional-timeline__label {
  animation-name: nac-label-fade-above;
}

/* Hover on markers */
.nacional-timeline__marker:hover .nacional-timeline__dot {
  border-color: var(--color-text) !important;
  transform: scale(1.3);
}

/* ---- Responsive: nacional timeline — tablet/mobile ---- */

@media (max-width: 48rem) {
  .nacional-timeline {
    margin: var(--space-xl) auto var(--space-md);
    padding: var(--space-lg) var(--space-md);
  }

  .nacional-timeline__track {
    margin: 2.5rem 0.5rem 3rem;
  }

  .nacional-timeline__label {
    font-size: 0.58rem;
  }

  .nacional-timeline__label small {
    font-size: 0.48rem;
  }

  .nacional-timeline__dot {
    width: 10px;
    height: 10px;
    border-width: 2px;
  }
}

/* At 375px / 320px: hide sublabels to prevent density crowding with 7 markers */
@media (max-width: 30rem) {
  .nacional-timeline__label small {
    display: none;
  }

  .nacional-timeline__track {
    margin: 1.5rem 0 2.5rem;
  }

  .nacional-timeline__label {
    font-size: 0.54rem;
  }
}

/* ---- Accessibility: skip timeline animations for reduced-motion users ---- */

@media (prefers-reduced-motion: reduce) {
  .nacional-timeline__progress {
    animation: none;
    width: 100%;
  }

  .nacional-timeline__dot {
    opacity: 1;
    transform: scale(1);
    animation: none !important;
    background: var(--color-nacional);
    border-color: var(--color-nacional);
  }

  .nacional-timeline__label {
    opacity: 1;
    transform: translateX(-50%);
    animation: none !important;
  }

  /* --above labels — same final state for reduced-motion */
  .nacional-timeline__marker--above .nacional-timeline__label {
    transform: translateX(-50%);
  }
}

