// Check all 3 timelines fit within viewport at 320px
const timelines = ['colonial-timeline', 'revolucion-timeline', 'nacional-timeline'].map(cls => {
  const el = document.querySelector(`.${cls}`);
  if (!el) return { cls, found: false };
  const rect = el.getBoundingClientRect();
  const scrollLeft = window.pageXOffset || document.documentElement.scrollLeft;
  // Check if the element extends beyond viewport width
  const elLeft = rect.left + scrollLeft;
  const elRight = rect.right + scrollLeft;
  return {
    cls,
    found: true,
    offsetWidth: el.offsetWidth,
    scrollWidth: el.scrollWidth,
    overflowsViewport: el.scrollWidth > document.documentElement.clientWidth,
    rightEdge: Math.round(rect.right)
  };
});
// Also check alberdi-quote
const quote = document.querySelector('.alberdi-quote');
const quoteInfo = quote ? {
  offsetWidth: quote.offsetWidth,
  paddingLeft: getComputedStyle(quote).paddingLeft,
  paddingRight: getComputedStyle(quote).paddingRight,
  rightEdge: Math.round(quote.getBoundingClientRect().right)
} : null;
({timelines, quoteInfo})

