// Container is 721px, minmax(min(100%, 320px), 1fr)
// min(100%, 320px) = 320px (since 721 > 320), so minmax(320px, 1fr)
// Number of columns = floor(721 / 320) = 2
// So yes, 2 columns would naturally fit at 768px
// Current: the @media (max-width: 48rem) forces 1fr, overriding the auto-fill

// Check the certeza grid too
const certezaGrids = document.querySelectorAll('.events-grid--certeza');
const certezaInfo = [...certezaGrids].map(g => ({
  id: g.closest('[id]')?.id || 'no-id',
  cols: getComputedStyle(g).gridTemplateColumns,
  width: g.offsetWidth
}));

// Check breakpoint calculation
({
  innerWidth: window.innerWidth,
  inRem: window.innerWidth / 16,
  issue: '768px = 48rem, max-width:48rem catches this, forcing 1-col instead of 2-col',
  certezaInfo
})

