// Get ALL matching rules for .events-grid from computed CSSOM
const grid = document.querySelector('.events-grid');

// Use matchedCSSRules alternative: check all media rules
const sheets = [...document.styleSheets];
const allMatchingRules = [];
sheets.forEach(sheet => {
  try {
    const processRuleList = (ruleList, mediaText) => {
      [...ruleList].forEach((rule, i) => {
        if (rule instanceof CSSMediaRule) {
          // Check if media applies
          const applies = window.matchMedia(rule.conditionText).matches;
          processRuleList(rule.cssRules, rule.conditionText + (applies ? ' [ACTIVE]' : ' [inactive]'));
        } else if (rule instanceof CSSStyleRule) {
          // Check if it matches .events-grid
          if (grid.matches(rule.selectorText)) {
            const gridTemplate = rule.style.gridTemplateColumns;
            if (gridTemplate) {
              allMatchingRules.push({mediaText, selector: rule.selectorText, gridTemplateColumns: gridTemplate});
            }
          }
        }
      });
    };
    processRuleList(sheet.cssRules, 'screen');
  } catch(e) { allMatchingRules.push({error: e.message}); }
});
allMatchingRules

