// The element has BOTH .events-grid AND .events-grid--certeza
// .events-grid--certeza has minmax(min(100%, 22rem), 1fr) = minmax(352px, 1fr)
// 720 / 352 = 2.04 → floor = 2 columns!
// But wait — both rules set gridTemplateColumns. The LAST rule wins.
// .events-grid: repeat(auto-fill, minmax(min(100%, 20rem), 1fr))
// .events-grid--certeza: repeat(auto-fill, minmax(min(100%, 22rem), 1fr))
// .events-grid--certeza comes LATER in the stylesheet → it wins

// At 768px with 22rem (352px) minimum:
// 720 / 352 = 2.04 → should give 2 columns

// But we're seeing 1 column = 720.8px. Let me check:
// 100% in the certeza grid context = 720px
// min(720px, 352px) = 352px
// minmax(352px, 1fr) with 720px container: floor(720/352) = 2 columns

// Hmm. Why is it giving 1?
// UNLESS: in CSS auto-fill, when minmax min > container_width / 2,
// we get 1 column.
// 720 / 352 = 2.04... so floor = 2, but maybe the gap is included in the calculation?

const grid = document.querySelector('.events-grid.events-grid--certeza');
const style = getComputedStyle(grid);
({
  gridTemplateColumns: style.gridTemplateColumns,
  columnGap: style.columnGap,
  gap: style.gap,
  width: grid.offsetWidth
})

